  /**
   * Resolves a type variable by traversing up the class hierarchy to find where it's defined
   * and what its actual type parameters are.
   *
   * @param typeVariable the type variable to resolve
   * @param clazz the class where we start the search (the concrete class)
   * @return the resolved actual type
   */
  private static Type resolveTypeVariableFromHierarchy(Type typeVariable, Class<?> clazz) {
    // Start from the given class and go up its hierarchy
    Class<?> currentClass = clazz;

    while (currentClass != null) {
      // Check if the type variable belongs to this class
      TypeVariable<?>[] classTypeVars = currentClass.getTypeParameters();
      for (int i = 0; i < classTypeVars.length; i++) {
        if (typeVariable.equals(classTypeVars[i])) {
          // This type variable is defined in currentClass
          // Look for the parameterized type from the superclass declaration
          Type genericSuperclass = currentClass.getGenericSuperclass();

          if (genericSuperclass instanceof ParameterizedType) {
            ParameterizedType ptype = (ParameterizedType) genericSuperclass;
            Type[] typeArgs = ptype.getActualTypeArguments();

            // We need to match this class's type variable with its parent's type arguments
            // The typeVars are in the same order as typeArgs
            if (i < typeArgs.length) {
              return typeArgs[i];
            }
          }
        }
      }

      // Also check interfaces for type variables
      Type[] genericInterfaces = currentClass.getGenericInterfaces();
      for (int j = 0; j < genericInterfaces.length; j++) {
        if (genericInterfaces[j] instanceof ParameterizedType) {
          ParameterizedType pInterface = (ParameterizedType) genericInterfaces[j];
          Type[] interfaceTypeArgs = pInterface.getActualTypeArguments();
          TypeVariable<?>[] interfaceTypeVars = currentClass.getInterfaces()[j].getTypeParameters();

          for (int k = 0; k < interfaceTypeVars.length; k++) {
            if (typeVariable.equals(interfaceTypeVars[k]) && k < interfaceTypeArgs.length) {
              return interfaceTypeArgs[k];
            }
          }
        }
      }

      // Move up to the superclass
      Type genericSuperclass = currentClass.getGenericSuperclass();
      if (genericSuperclass instanceof ParameterizedType) {
        // If the superclass is parameterized, we need to resolve type variables accordingly
        ParameterizedType ptype = (ParameterizedType) genericSuperclass;
        Class<?> superClass = (Class<?>) ptype.getRawType();

        // We need to map the type variables from the superclass back to actual types
        Type[] superTypeArgs = ptype.getActualTypeArguments();
        TypeVariable<?>[] superTypeVars = superClass.getTypeParameters();

        // Look for type variable in the superclass's type parameters
        for (int idx = 0; idx < superTypeVars.length; idx++) {
          if (typeVariable.equals(superTypeVars[idx])) {
            // Found in superclass, return the corresponding actual type
            return superTypeArgs[idx];
          }
        }

        // If the type variable wasn't found in this class's own type params,
        // but it's still a type variable, we need to recursively check the parent
        for (int idx = 0; idx < superTypeArgs.length; idx++) {
          if (superTypeArgs[idx] instanceof TypeVariable<?>) {
            // Recursively resolve if the type argument itself is another type var
            Type resolved = resolveTypeVariableFromHierarchy(superTypeArgs[idx], superClass);
            if (!resolved.equals(superTypeArgs[idx])) { // if it was successfully resolved
              // Update the type args array and rebuild the ParameterizedType
              Type[] newArgs = superTypeArgs.clone();
              newArgs[idx] = resolved;
              ptype = new ParameterizedTypeImpl(ptype.getRawType(), newArgs, ptype.getOwnerType());

              // Now resolve the original type variable again
              Type resolvedOriginal = resolveTypeVariableFromHierarchy(typeVariable, superClass);
              if (!(resolvedOriginal instanceof TypeVariable<?>)) {
                return resolvedOriginal;
              }
            }
          }
        }
      }

      // Continue with the raw superclass to go up the hierarchy
      currentClass = currentClass.getSuperclass();
    }

    // If we get here, we couldn't resolve the type variable
    throw new UnsupportedOperationException("Could not resolve type variable " + typeVariable 
        + " from hierarchy starting at " + clazz.getName());
  }
}

