   * Resolves a type variable by looking at the generic superclass of a concrete class.
   *
   * @param typeVariable the type variable to resolve
   * @param clazz the concrete class (which may extend a parameterized generic class)
   * @return the resolved actual type
   */
  private static Type resolveTypeVariableFromHierarchy(Type typeVariable, Class<?> clazz) {
    // Get the generic superclass which should be a ParameterizedType for cases like:
    // class Bar extends Foo<String, Integer> 
    Type genericSuperclass = clazz.getGenericSuperclass();

    if (genericSuperclass instanceof ParameterizedType) {
      ParameterizedType paramType = (ParameterizedType) genericSuperclass;
      Class<?> superClass = (Class<?>) paramType.getRawType();

      // Find the index of the type variable in the superclass's type parameters
      TypeVariable<?>[] superClassTypeVars = superClass.getTypeParameters();
      for (int i = 0; i < superClassTypeVars.length; i++) {
        if (typeVariable.equals(superClassTypeVars[i])) {
          // Get the actual type argument at the same position
          Type[] actualTypeArgs = paramType.getActualTypeArguments();
          if (i < actualTypeArgs.length) {
            return actualTypeArgs[i];
          }
        }
      }
    }

    // If not found in immediate superclass, recursively check higher up the hierarchy
    Class<?> superClass = clazz.getSuperclass();
    if (superClass != null && superClass != Object.class) {
      return resolveTypeVariableFromHierarchy(typeVariable, superClass);
    }

    // If we get here, we couldn't resolve the type variable
    throw new UnsupportedOperationException("Could not resolve type variable " + typeVariable 
        + " from hierarchy starting at " + clazz.getName());
  }
}

